tests.testString:
const rect = { type: "rectangle", width: 9, height: 13 }
const result = calculateArea(rect)

const match = String(result).match(/-?\d+(\.\d+)?/)
assert.isOk(match)

const value = Number(match[0])
const expected = 9 * 13

assert.approximately(value, expected, 0.01)

const triangle = { type: "triangle", base: 11, height: 16 }
const result = calculateArea(triangle)

const match = String(result).match(/-?\d+(\.\d+)?/)
assert.isOk(match)

const value = Number(match[0])
const expected = 0.5 * 11 * 16

assert.approximately(value, expected, 0.01)
